const row = $json;

// ---------- helpers ----------

function cleanBoolFlag(x) {
  if (x === null || x === undefined) return null;
  // Some are stored as 0/1 ints in metadata
  const n = Number(x);
  if (!Number.isNaN(n)) return n !== 0 ? 'Yes' : 'No';
  const s = String(x).toLowerCase();
  if (['true', 't', 'yes', 'y', '1'].includes(s)) return 'Yes';
  if (['false', 'f', 'no', 'n', '0'].includes(s)) return 'No';
  return null;
}

function parseJsonArray(value) {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  if (typeof value === 'object') return Object.values(value);
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }
  return [];
}

// Build "System / Location – Terminal" label
function formatLocationEntry(p, priceKey) {
  if (!p || typeof p !== 'object') return {
    label: 'Unknown location / terminal',
    price: null,
  };

  const system   = String(p.star_system_name || '').trim();
  const planet   = String(p.planet_name      || '').trim();
  const city     = String(p.city_name        || '').trim();
  const orbit    = String(p.orbit_name       || '').trim();
  const terminal = String(p.terminal_name    || '').trim();
  const code     = String(p.terminal_code    || '').trim();

  let locBits = [];
  if (system) locBits.push(system);
  if (planet) locBits.push(planet);
  if (city)   locBits.push(city);
  if (orbit && !locBits.includes(orbit)) locBits.push(orbit);

  let label = '';
  if (locBits.length) label = locBits.join(' / ');
  if (terminal) label += (label ? ' – ' : '') + terminal;
  if (code)     label += ` (${code})`;

  if (!label) label = 'Unknown location / terminal';

  const price = priceKey && p[priceKey] != null
    ? Number(p[priceKey])
    : null;

  return { label, price };
}

// Select 2 lowest, 2 highest, 1 middle by price
function pickFiveByPrice(entries) {
  const withPrice = entries
    .filter(e => typeof e.price === 'number' && !Number.isNaN(e.price))
    .sort((a, b) => a.price - b.price);

  if (withPrice.length <= 5) return withPrice;

  const first = withPrice[0];
  const second = withPrice[1];
  const last = withPrice[withPrice.length - 1];
  const secondLast = withPrice[withPrice.length - 2];
  const midIndex = Math.floor(withPrice.length / 2);
  const mid = withPrice[midIndex];

  // Deduplicate if there are very few unique prices
  const result = [];
  const seen = new Set();
  for (const e of [first, second, mid, secondLast, last]) {
    const key = `${e.label}|${e.price}`;
    if (!seen.has(key)) {
      seen.add(key);
      result.push(e);
    }
  }
  return result;
}

// ---------- parse arrays from row ----------

const purchasePointsRaw = parseJsonArray(row.purchase_points);
const rentalPointsRaw   = parseJsonArray(row.rental_points);
const storePricesRaw    = parseJsonArray(row.store_prices);

const purchaseEntries = purchasePointsRaw.map(p => formatLocationEntry(p, 'price_buy'));
const rentalEntries   = rentalPointsRaw.map(p => formatLocationEntry(p, 'price_rent'));

const storeEntries = storePricesRaw.map(sp => {
  if (!sp || typeof sp !== 'object') return null;
  const currency = String(sp.currency || '').trim() || 'N/A';
  const price    = sp.price != null ? Number(sp.price) : null;
  const gv       = String(sp.game_version || '').trim();
  const onSale   = cleanBoolFlag(sp.on_sale);
  return { currency, price, gameVersion: gv, onSale };
}).filter(Boolean);

// ---------- container sizes ----------

let containerSizes = [];

if (row.container_sizes) {
  // If your SQL already selects metadata->'raw'->>'container_sizes' AS container_sizes
  containerSizes = String(row.container_sizes)
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
} else if (row.metadata && row.metadata.raw && row.metadata.raw.container_sizes) {
  // Fallback: pull directly from metadata.raw if needed
  containerSizes = String(row.metadata.raw.container_sizes)
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
}

// Normalize to ints and only keep valid SCU sizes
const validSizes = [1, 2, 4, 8, 16, 24, 32];
containerSizes = containerSizes
  .map(s => Number(s))
  .filter(n => Number.isInteger(n) && validSizes.includes(n))
  .sort((a, b) => a - b);


// ---------- shared header ----------

const headerLines = [];

headerLines.push(`# ${row.name}`);
headerLines.push('');

if (row.name_full && row.name_full !== row.name) {
  headerLines.push(`- **Full Name:** ${row.name_full}`);
}

if (row.company_name) {
  headerLines.push(`- **Manufacturer:** ${row.company_name}`);
}

headerLines.push(`- **UEX Vehicle ID:** ${row.uex_vehicle_id || 'N/A'}`);

if (row.scu != null) {
  let line = `- **SCU Capacity:** ${row.scu}`;

  if (containerSizes && containerSizes.length) {
    line += ` (Supports ${containerSizes.join(', ')} containers)`;
  }

  headerLines.push(line);
}


const crewBits = [];
if (row.crew_min != null) crewBits.push(`Min ${row.crew_min}`);
if (row.crew_max != null) crewBits.push(`Max ${row.crew_max}`);
if (crewBits.length) {
  headerLines.push(`- **Crew:** ${crewBits.join(' / ')}`);
}

if (row.pad_type) {
  headerLines.push(`- **Pad Size:** ${row.pad_type}`);
}

const roleTags = [];
if (cleanBoolFlag(row.is_military)   === 'Yes') roleTags.push('Military');
if (cleanBoolFlag(row.is_civilian)   === 'Yes') roleTags.push('Civilian');
if (cleanBoolFlag(row.is_industrial) === 'Yes') roleTags.push('Industrial');
if (cleanBoolFlag(row.is_exploration)=== 'Yes') roleTags.push('Exploration');
if (cleanBoolFlag(row.is_mining)     === 'Yes') roleTags.push('Mining');
if (cleanBoolFlag(row.is_transport)  === 'Yes') roleTags.push('Transport');
if (roleTags.length) {
  headerLines.push(`- **Role Flags:** ${roleTags.join(', ')}`);
}

const flags = [];
const fSpaceship = cleanBoolFlag(row.is_spaceship);
const fGround    = cleanBoolFlag(row.is_ground_vehicle);
const fConcept   = cleanBoolFlag(row.is_concept);
const fQuantum   = cleanBoolFlag(row.is_quantum_capable);
if (fSpaceship) flags.push(`Spaceship: ${fSpaceship}`);
if (fGround)    flags.push(`Ground Vehicle: ${fGround}`);
if (fConcept)   flags.push(`Concept: ${fConcept}`);
if (fQuantum)   flags.push(`Quantum-Capable: ${fQuantum}`);
if (flags.length) {
  headerLines.push(`- **Flags:** ${flags.join(' | ')}`);
}

if (row.game_version) {
  headerLines.push(`- **Last Seen Game Version (UEX):** ${row.game_version}`);
}

const purchaseCount = Number(row.purchase_count ?? purchaseEntries.length) || 0;
const rentalCount   = Number(row.rental_count   ?? rentalEntries.length)   || 0;
const storeCount    = Number(row.store_count    ?? storeEntries.length)    || 0;

headerLines.push(`- **In-Game Purchase Offers (aUEC):** ${purchaseCount}`);
headerLines.push(`- **In-Game Rental Offers (aUEC):** ${rentalCount}`);
headerLines.push(`- **Pledge Store Entries:** ${storeCount}`);
headerLines.push('');

// ---------- purchase summary (smart 5) ----------

let purchaseSummary = [];
let purchaseSuffix = '';

if (purchaseCount <= 5) {
  purchaseSummary = purchaseEntries;
} else {
  purchaseSummary = pickFiveByPrice(purchaseEntries);
  purchaseSuffix = ` (${purchaseSummary.length} of ${purchaseCount})`;
}

// ---------- SUMMARY MARKDOWN ----------

const summaryLines = [...headerLines];

summaryLines.push(`## In-Game Purchase Locations${purchaseSuffix}`);
summaryLines.push('');
summaryLines.push('> _Note: Price data is based on UEX reports and may change with patches._');
summaryLines.push('');

if (purchaseSummary.length === 0) {
  summaryLines.push('_No confirmed in-game purchase locations recorded yet for this vehicle._');
} else {
  for (const p of purchaseSummary) {
    const priceText = (typeof p.price === 'number' && !Number.isNaN(p.price))
      ? `${p.price.toLocaleString('en-US')} aUEC`
      : 'aUEC price unknown';
    summaryLines.push(`- ${p.label}: ${priceText}`);
  }
  if (purchaseCount > purchaseSummary.length) {
    summaryLines.push('… and more');
  }
}

// Rentals summary (simple first 5)
summaryLines.push('');
summaryLines.push('## In-Game Rental Locations');
summaryLines.push('');
summaryLines.push('> _Where this ship can be rented in-game (if available)._');
summaryLines.push('');

if (rentalEntries.length === 0) {
  summaryLines.push('_No rental locations recorded yet for this vehicle._');
} else {
  const rentalsToShow = rentalEntries.slice(0, 5);
  for (const r of rentalsToShow) {
    const priceText = (typeof r.price === 'number' && !Number.isNaN(r.price))
      ? `${r.price.toLocaleString('en-US')} aUEC`
      : 'aUEC price unknown';
    summaryLines.push(`- ${r.label}: ${priceText}`);
  }
  if (rentalEntries.length > rentalsToShow.length) {
    summaryLines.push('… and more');
  }
}

// Store prices summary
summaryLines.push('');
summaryLines.push('## Pledge Store Snapshot');
summaryLines.push('');
summaryLines.push('> _Non-exhaustive summary of recent pledge prices from UEX._');
summaryLines.push('');

if (storeEntries.length === 0) {
  summaryLines.push('_No pledge store data recorded yet for this vehicle._');
} else {
  const byCurrency = {};
  for (const sp of storeEntries) {
    if (!byCurrency[sp.currency]) byCurrency[sp.currency] = [];
    byCurrency[sp.currency].push(sp);
  }

  for (const [currency, list] of Object.entries(byCurrency)) {
    const prices = list
      .map(x => x.price)
      .filter(x => typeof x === 'number' && !Number.isNaN(x))
      .sort((a, b) => a - b);
    if (!prices.length) continue;

    const min = prices[0];
    const max = prices[prices.length - 1];
    summaryLines.push(
      `- ${currency}: ${min === max
        ? `${min} (typical)`
        : `${min} – ${max}`}`,
    );
  }
}

// ---------- DETAILED MARKDOWN ----------

const detailedLines = [...headerLines];

// Detailed purchases
detailedLines.push('## In-Game Purchase Locations (Detailed)');
detailedLines.push('');
detailedLines.push('> _Full list of UEX-reported purchase offers for this ship._');
detailedLines.push('');

if (purchaseEntries.length === 0) {
  detailedLines.push('_No confirmed in-game purchase locations recorded yet for this vehicle._');
} else {
  for (const p of purchaseEntries) {
    const priceText = (typeof p.price === 'number' && !Number.isNaN(p.price))
      ? `${p.price.toLocaleString('en-US')} aUEC`
      : 'aUEC price unknown';
    detailedLines.push(`- ${p.label}: ${priceText}`);
  }
}

// Detailed rentals
detailedLines.push('');
detailedLines.push('## In-Game Rental Locations (Detailed)');
detailedLines.push('');
detailedLines.push('> _Full list of UEX-reported rental offers for this ship._');
detailedLines.push('');

if (rentalEntries.length === 0) {
  detailedLines.push('_No rental locations recorded yet for this vehicle._');
} else {
  for (const r of rentalEntries) {
    const priceText = (typeof r.price === 'number' && !Number.isNaN(r.price))
      ? `${r.price.toLocaleString('en-US')} aUEC`
      : 'aUEC price unknown';
    detailedLines.push(`- ${r.label}: ${priceText}`);
  }
}

// Detailed store prices
detailedLines.push('');
detailedLines.push('## Pledge Store History (Detailed)');
detailedLines.push('');
detailedLines.push('> _Each row reflects a recorded pledge-store listing from UEX._');
detailedLines.push('');

if (storeEntries.length === 0) {
  detailedLines.push('_No pledge store data recorded yet for this vehicle._');
} else {
  for (const sp of storeEntries) {
    const priceText = (typeof sp.price === 'number' && !Number.isNaN(sp.price))
      ? `${sp.price.toLocaleString('en-US')} ${sp.currency}`
      : `Price unknown (${sp.currency})`;
    const onSale = sp.onSale ? ` (On Sale: ${sp.onSale})` : '';
    const gv = sp.gameVersion ? ` [Game: ${sp.gameVersion}]` : '';
    detailedLines.push(`- ${priceText}${gv}${onSale}`);
  }
}

// ---------- file paths ----------

const slug = String(row.slug || row.name || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const filePathSummary  = `/RAG/KB/vehicles/${slug}.md`;
const filePathDetailed = `/RAG/KB/vehicles/${slug}_detailed.md`;

return [
  {
    json: {
      vehicle_id: row.id,
      slug,
      name: row.name,

      markdown_summary:  summaryLines.join('\n'),
      filePath_summary:  filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

